#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        unsigned long long sum = 0ULL;
        unsigned long long fact = 1ULL;
        for (int i = 0; i <= n; ++i) {
            if (i == 0) fact = 1ULL;
            else fact *= (unsigned long long)i;
            sum += fact;
        }
        printf("The sum of the series is %llu\n", sum);
    }
    return 0;
}

