import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    T = int(data[0])
    out = []
    idx = 1
    for _ in range(T):
        n = int(data[idx]); idx += 1
        total = 0
        fact = 1
        for i in range(n + 1):
            if i == 0:
                fact = 1
            else:
                fact *= i
            total += fact
        out.append(f"The sum of the series is {total}")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

